+    assert!(snap.full_validation_trigger_ppm <= 1_000_000);
+    assert!(snap.repair_trigger_ppm <= 1_000_000);
+    // Pressure regime must be a valid code.
+    assert!(snap.pressure_regime_code <= 3);
